<script>
// If - block comment before empty body
if(a)/* comment */;

// If - line comment before empty body
if(a)// comment
;

// If - block comment before empty body, with else
if(a)/* comment */;else{expr;}

// If - line comment before empty body, with else
if(a)// comment
;else{expr;}

// While - block comment before empty body
while(a)/* comment */;

// While - line comment before empty body
while(a)// comment
;
</script>
